# Adaptive rejection sampling for univariate log-concave densities.
# Reference: Gilks and Wild (1992), Applied Statistics 41(2), 337-348.

.ars_stop <- function(...) stop(sprintf(...), call. = FALSE)

.validate_inputs <- function(density, n, domain, initial, max_iter, tol) {
  if (!is.function(density)) .ars_stop("density must be a function.")
  if (!is.numeric(n) || length(n) != 1 || !is.finite(n) || n != as.integer(n) || n <= 0) {
    .ars_stop("n must be a positive integer.")
  }
  if (!is.numeric(domain) || length(domain) != 2 || any(is.na(domain)) || domain[1] >= domain[2]) {
    .ars_stop("domain must be a numeric vector c(lower, upper) with lower < upper.")
  }
  if (!is.numeric(initial) || length(initial) < 3 || any(!is.finite(initial))) {
    .ars_stop("initial must contain at least three finite numeric points.")
  }
  if (any(initial <= domain[1]) || any(initial >= domain[2])) {
    .ars_stop("all initial points must be strictly inside domain.")
  }
  if (!is.numeric(max_iter) || length(max_iter) != 1 || max_iter <= 0) {
    .ars_stop("max_iter must be positive.")
  }
  if (!is.numeric(tol) || length(tol) != 1 || tol <= 0 || !is.finite(tol)) {
    .ars_stop("tol must be a positive finite number.")
  }
  invisible(TRUE)
}

.eval_log_density <- function(density, x) {
  y <- density(x)
  if (!is.numeric(y) || length(y) != length(x)) {
    .ars_stop("density must return a numeric vector with the same length as x.")
  }
  if (any(is.na(y)) || any(y < 0)) {
    .ars_stop("density returned NA or negative values.")
  }
  out <- rep(-Inf, length(x))
  positive <- y > 0
  out[positive] <- log(y[positive])
  out
}

.derivative <- function(density, x, domain, rel_step = 1e-5) {
  step <- rel_step * pmax(1, abs(x))
  left_room <- x - domain[1]
  right_room <- domain[2] - x
  step <- pmin(step, left_room / 2, right_room / 2)
  if (any(step <= 0 | !is.finite(step))) .ars_stop("cannot compute derivatives at initial/support points.")
  (.eval_log_density(density, x + step) - .eval_log_density(density, x - step)) / (2 * step)
}

.check_hull_points <- function(x, h, hp, tol = 1e-7) {
  if (any(!is.finite(h)) || any(!is.finite(hp))) {
    .ars_stop("density must be positive and finite at all hull points.")
  }
  if (any(diff(hp) > tol)) {
    .ars_stop("non-log-concave density detected: log-density slopes increased.")
  }
  TRUE
}

.intersections <- function(x, h, hp, domain) {
  k <- length(x)
  z <- numeric(k + 1)
  z[1] <- domain[1]
  z[k + 1] <- domain[2]
  for (i in seq_len(k - 1)) {
    denom <- hp[i] - hp[i + 1]
    if (denom <= 0) .ars_stop("non-log-concave density detected while building hull.")
    z[i + 1] <- (h[i + 1] - h[i] - x[i + 1] * hp[i + 1] + x[i] * hp[i]) / denom
  }
  if (any(diff(z) <= 0) || any(z[-1] <= domain[1]) || any(z[-length(z)] >= domain[2])) {
    .ars_stop("invalid hull intersections; check domain, initial points, and log-concavity.")
  }
  z
}

.log_integral_exp_line <- function(a, b, slope) {
  if (is.infinite(a) && slope <= 0) return(Inf)
  if (is.infinite(b) && slope >= 0) return(Inf)
  if (abs(slope) < 1e-12) return(log(b - a))
  vals <- slope * c(a, b)
  m <- max(vals)
  m + log(abs(exp(vals[2] - m) - exp(vals[1] - m))) - log(abs(slope))
}

.build_hull <- function(x, density, domain, tol) {
  o <- order(x)
  x <- unique(x[o])
  h <- .eval_log_density(density, x)
  hp <- .derivative(density, x, domain)
  .check_hull_points(x, h, hp, tol)
  z <- .intersections(x, h, hp, domain)
  intercept <- h - hp * x
  logw <- numeric(length(x))
  for (i in seq_along(x)) {
    logw[i] <- intercept[i] + .log_integral_exp_line(z[i], z[i + 1], hp[i])
  }
  if (any(!is.finite(logw))) {
    .ars_stop("upper hull has infinite mass; add better initial points or restrict the domain.")
  }
  list(x = x, h = h, hp = hp, z = z, intercept = intercept, logw = logw)
}

.sample_piece <- function(hull) {
  log_total <- max(hull$logw) + log(sum(exp(hull$logw - max(hull$logw))))
  probs <- exp(hull$logw - log_total)
  i <- sample.int(length(probs), 1, prob = probs)
  a <- hull$z[i]
  b <- hull$z[i + 1]
  s <- hull$hp[i]
  u <- runif(1)
  if (abs(s) < 1e-12) {
    x <- a + u * (b - a)
  } else if (is.infinite(b)) {
    x <- a + log(1 - u) / s
  } else if (is.infinite(a)) {
    x <- b + log(u) / s
  } else {
    ea <- exp(s * a)
    eb <- exp(s * b)
    x <- log(ea + u * (eb - ea)) / s
  }
  list(x = x, log_upper = hull$intercept[i] + hull$hp[i] * x)
}

.lower_hull <- function(x, hull) {
  i <- findInterval(x, hull$x)
  if (i < 1 || i >= length(hull$x)) return(-Inf)
  x0 <- hull$x[i]
  x1 <- hull$x[i + 1]
  h0 <- hull$h[i]
  h1 <- hull$h[i + 1]
  h0 + (h1 - h0) * (x - x0) / (x1 - x0)
}

.insert_point <- function(x, new_x, density, domain, tol) {
  if (any(abs(x - new_x) < sqrt(.Machine$double.eps) * pmax(1, abs(new_x)))) return(x)
  .build_hull(c(x, new_x), density, domain, tol)$x
}

ars <- function(density, n, domain = c(-Inf, Inf), initial = NULL,
                max_iter = 100000, tol = 1e-7, seed = NULL) {
  if (!is.null(seed)) set.seed(seed)
  if (is.null(initial)) {
    if (all(is.finite(domain))) {
      initial <- seq(domain[1], domain[2], length.out = 5)[2:4]
    } else if (is.finite(domain[1])) {
      initial <- domain[1] + c(0.25, 1, 3)
    } else if (is.finite(domain[2])) {
      initial <- domain[2] - c(3, 1, 0.25)
    } else {
      initial <- c(-2, 0, 2)
    }
  }
  .validate_inputs(density, n, domain, initial, max_iter, tol)
  hull <- .build_hull(initial, density, domain, tol)
  samples <- numeric(n)
  accepted <- 0L
  iter <- 0L
  while (accepted < n) {
    iter <- iter + 1L
    if (iter > max_iter) .ars_stop("max_iter exceeded before collecting all samples.")
    proposal <- .sample_piece(hull)
    x <- proposal$x
    if (!is.finite(x) || x <= domain[1] || x >= domain[2]) next
    log_u <- log(runif(1))
    low <- .lower_hull(x, hull)
    if (log_u <= low - proposal$log_upper) {
      accepted <- accepted + 1L
      samples[accepted] <- x
      next
    }
    hx <- .eval_log_density(density, x)
    if (!is.finite(hx)) .ars_stop("density was zero or non-finite inside the support.")
    if (hx - proposal$log_upper > 1e-6) {
      .ars_stop("non-log-concave density detected: log density exceeded upper hull.")
    }
    if (log_u <= hx - proposal$log_upper) {
      accepted <- accepted + 1L
      samples[accepted] <- x
    }
    hull <- .build_hull(c(hull$x, x), density, domain, tol)
  }
  samples
}

.print_result <- function(name, passed, samples = NULL, target_mean = NA_real_, target_sd = NA_real_) {
  status <- if (isTRUE(passed)) "PASS" else "FAIL"
  if (is.null(samples)) {
    cat(sprintf("%s: %s\n", name, status))
  } else {
    cat(sprintf(
      "%s: %s mean=%.4f target_mean=%.4f sd=%.4f target_sd=%.4f\n",
      name, status, mean(samples), target_mean, sd(samples), target_sd
    ))
  }
  invisible(passed)
}

test <- function() {
  set.seed(20260629)
  results <- logical()

  normal <- ars(dnorm, 5000, initial = c(-2, 0, 2))
  write.table(normal, "/app/normal_samples.txt", row.names = FALSE, col.names = FALSE)
  normal_ok <- abs(mean(normal)) < 0.06 && abs(sd(normal) - 1) < 0.06 &&
    suppressWarnings(ks.test(normal, "pnorm")$p.value) > 0.01
  results["NORMAL_STANDARD"] <- .print_result("NORMAL_STANDARD", normal_ok, normal, 0, 1)

  exp_density <- function(x) ifelse(x >= 0, dexp(x, rate = 2), 0)
  expo <- ars(exp_density, 5000, domain = c(0, Inf), initial = c(0.1, 0.8, 2.0))
  exp_ok <- abs(mean(expo) - 0.5) < 0.035 && abs(sd(expo) - 0.5) < 0.04 &&
    suppressWarnings(ks.test(expo, "pexp", rate = 2)$p.value) > 0.01
  results["EXPONENTIAL_RATE_2"] <- .print_result("EXPONENTIAL_RATE_2", exp_ok, expo, 0.5, 0.5)

  gamma_density <- function(x) ifelse(x > 0, dgamma(x, shape = 3, rate = 2), 0)
  gamma_s <- ars(gamma_density, 5000, domain = c(0, Inf), initial = c(0.2, 1, 3))
  gamma_ok <- abs(mean(gamma_s) - 1.5) < 0.06 && abs(sd(gamma_s) - sqrt(3) / 2) < 0.06 &&
    suppressWarnings(ks.test(gamma_s, "pgamma", shape = 3, rate = 2)$p.value) > 0.01
  results["GAMMA_SHAPE_3_RATE_2"] <- .print_result(
    "GAMMA_SHAPE_3_RATE_2", gamma_ok, gamma_s, 1.5, sqrt(3) / 2
  )

  invalid_ok <- inherits(try(ars(dnorm, -5), silent = TRUE), "try-error")
  results["INVALID_INPUTS"] <- .print_result("INVALID_INPUTS", invalid_ok)

  bimodal <- function(x) 0.5 * dnorm(x, -3, 0.6) + 0.5 * dnorm(x, 3, 0.6)
  nonlc_ok <- inherits(try(ars(bimodal, 20, initial = c(-4, 0, 4)), silent = TRUE), "try-error")
  results["NON_LOG_CONCAVE_CHECK"] <- .print_result("NON_LOG_CONCAVE_CHECK", nonlc_ok)

  invisible(results)
}
